async function run() {
  await pool.query("DELETE FROM reviews");
  console.log("Cleared existing reviews");

  let count = 0;
  for (const r of reviews) {
    await pool.query(
      `INSERT INTO reviews (guest_name, platform, rating, property, stay_date, review_text, status, is_featured, created_at, updated_at)
       VALUES ($1, $2, $3, $4, $5, $6, $7, $8, NOW(), NOW())`,
      [r.guest_name, r.platform, r.rating, r.property, r.stay_date, r.review_text, "approved", true]
    );
    count++;
  }

  const { rows } = await pool.query(
    "SELECT COUNT(*) as count, AVG(rating) as avg, COUNT(DISTINCT property) as properties FROM reviews"
  );
  console.log(`Imported ${count} reviews | Avg: ${Number(rows[0].avg).toFixed(2)} stars | Properties: ${rows[0].properties}`);

  const { rows: byProp } = await pool.query(
    "SELECT property, COUNT(*) as count FROM reviews GROUP BY property ORDER BY count DESC"
  );
  for (const r of byProp) {
    console.log(`  ${r.property}: ${r.count} reviews`);
  }

  await pool.end();
}

run().catch((err) => {
  console.error(err);
  process.exit(1);
});
